const SUPABASE_URL = $vars.STAG_SUPABASE_URL;
const SUPABASE_KEY = $vars.STAG_SUPABASE_SERVICE_ROLE_KEY;
if (!SUPABASE_URL || !SUPABASE_KEY) throw new Error('Set STAG_SUPABASE_URL and STAG_SUPABASE_SERVICE_ROLE_KEY in n8n Variables');
const headers = { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` };
const queued = await this.helpers.httpRequest({ method: 'GET', url: `${SUPABASE_URL}/rest/v1/social_content_queue?select=meeting_record_id&meeting_record_id=not.is.null`, headers, json: true });
const queuedIds = (Array.isArray(queued) ? queued : []).map(r => r.meeting_record_id);
const sevenDaysAgo = new Date(Date.now() - 7*24*60*60*1000).toISOString();
const meetings = await this.helpers.httpRequest({ method: 'GET', url: `${SUPABASE_URL}/rest/v1/meeting_records?select=*&created_at=gte.${sevenDaysAgo}&order=created_at.desc&limit=10`, headers, json: true });
const unprocessed = (Array.isArray(meetings) ? meetings : []).filter(m => !queuedIds.includes(m.id));
if (unprocessed.length === 0) return [{ json: { _empty: true, message: 'No unprocessed meetings found' } }];
return unprocessed.map(m => ({ json: m }));

const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || response.message?.content || '{}';

let topics;
try {
  topics = JSON.parse(content);
  if (!Array.isArray(topics)) topics = [topics];
} catch (e) {
  const match = content.match(/\[.*\]/s);
  topics = match ? JSON.parse(match[0]) : [{ topic: content, angle: 'General insight', key_insight: content, personal_tie_in: '', hormozi_framework: 'value_equation', framework_visual: 'architecture', content_pillar: null, principle_count: 0, transcript_evidence: '' }];
}

return topics.map(t => ({ json: { ...t, meeting_record_id: $node['Fetch Unprocessed Meetings'].json.id, rag_context: $node['RAG Personal Context'].json, content_pillar: t.content_pillar || null, principle_count: parseInt(t.principle_count) || 0, transcript_evidence: t.transcript_evidence || '' } }));

const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || response.message?.content || '{}';

let post;
try {
  post = JSON.parse(content);
} catch (e) {
  const match = content.match(/\{.*\}/s);
  post = match ? JSON.parse(match[0]) : { post_text: content, cta_text: '', cta_url: 'https://amadutown.com', hashtags: ['business', 'automation'], hormozi_framework: {} };
}

const prev = $node['Parse Topics'].json;
const principleCount = prev.principle_count || 0;
const contentFormat = principleCount >= 3 ? 'carousel' : 'single_image';

let imagePrompt;
try {
  const webhookPrompts = $node['Manual Trigger Webhook'].first()?.json?.prompts;
  if (webhookPrompts?.imageGeneration) {
    imagePrompt = webhookPrompts.imageGeneration
      .replace('{framework_visual_type}', prev.framework_visual || 'architecture')
      .replace('{topic}', prev.topic || '')
      .replace('{key_elements}', prev.key_insight || '');
  }
} catch (e) { /* scheduled run - no webhook data */ }

if (!imagePrompt) {
  imagePrompt = `Create a clean, professional ${prev.framework_visual} illustration for LinkedIn. Topic: ${prev.topic}. Style: deep navy (#121E31) background, gold (#D4AF37) accents, platinum white (#EAECEE) text, geometric sans-serif headings, premium minimal aesthetic, no stock photos, pure diagram/framework visual, 1:1 aspect ratio.`;
}

return [{ json: {
  meeting_record_id: prev.meeting_record_id,
  platform: 'linkedin',
  status: 'draft',
  post_text: post.post_text,
  companion_post_text: post.companion_post_text || null,
  cta_text: post.cta_text || null,
  cta_url: post.cta_url || 'https://amadutown.com',
  hashtags: post.hashtags || [],
  framework_visual_type: prev.framework_visual,
  content_format: contentFormat,
  content_pillar: post.content_pillar || prev.content_pillar || null,
  topic_extracted: { topic: prev.topic, angle: prev.angle, key_insight: prev.key_insight, personal_tie_in: prev.personal_tie_in, framework_visual: prev.framework_visual, transcript_evidence: prev.transcript_evidence || '' },
  hormozi_framework: post.hormozi_framework || {},
  rag_context: prev.rag_context || {},
  image_prompt: imagePrompt,
  voiceover_text: post.post_text,
  principle_count: principleCount
} }];

const geminiResponse = $input.first().json;
const prev = $node['Format Post Data'].json;

let imageBase64 = null;
let imageMimeType = 'image/png';

if (geminiResponse.candidates?.[0]?.content?.parts) {
  for (const part of geminiResponse.candidates[0].content.parts) {
    if (part.inlineData) {
      imageBase64 = part.inlineData.data;
      imageMimeType = part.inlineData.mimeType || 'image/png';
      break;
    }
  }
}

return [{ json: { ...prev, imageBase64, imageMimeType, hasImage: !!imageBase64 } }];

const SUPABASE_URL = $vars.STAG_SUPABASE_URL;
const SUPABASE_KEY = $vars.STAG_SUPABASE_SERVICE_ROLE_KEY;
if (!SUPABASE_URL || !SUPABASE_KEY) throw new Error('Set STAG_SUPABASE_URL and STAG_SUPABASE_SERVICE_ROLE_KEY in n8n Variables');
const data = $node['Process Image'].json;
const row = {
  meeting_record_id: data.meeting_record_id,
  platform: data.platform || 'linkedin',
  status: 'draft',
  post_text: data.post_text,
  companion_post_text: data.companion_post_text || null,
  cta_text: data.cta_text || null,
  cta_url: data.cta_url || 'https://amadutown.com',
  hashtags: data.hashtags || [],
  framework_visual_type: data.framework_visual_type || null,
  content_format: 'single_image',
  content_pillar: data.content_pillar || null,
  topic_extracted: data.topic_extracted || {},
  hormozi_framework: data.hormozi_framework || {},
  rag_context: data.rag_context || {},
  image_prompt: data.image_prompt || '',
  voiceover_text: data.voiceover_text || ''
};
const result = await this.helpers.httpRequest({
  method: 'POST',
  url: `${SUPABASE_URL}/rest/v1/social_content_queue`,
  headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=representation' },
  body: row,
  json: true
});
return [{ json: Array.isArray(result) ? result[0] : result }];

